import { useEffect, useMemo, useState } from 'react'
import { ArrowRight, ExternalLink, FileCheck2, Send, UserRound } from 'lucide-react'
import { productToSummary } from '@/domain/products/adapters'
import { useAppState } from '@/lib/appState'
import type { DirectusUser, Product, ProductSubmission } from '@/lib/types'
import { fetchSubmissions, updateSubmissionStatus } from '@/features/workflow/api'

function titleCase(value: string | null | undefined) {
  return (value ?? 'unknown').replaceAll('_', ' ').replace(/\b\w/g, (c) => c.toUpperCase())
}

function formatDate(iso: string | null | undefined) {
  if (!iso) return 'No date'
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

function relationName(value: unknown): string | null {
  if (!value || typeof value === 'string') return null
  if (typeof value === 'object' && 'name' in value && typeof value.name === 'string') return value.name
  if (typeof value === 'object' && 'title' in value && typeof value.title === 'string') return value.title
  return null
}

function userName(value: string | DirectusUser | null | undefined) {
  if (!value || typeof value === 'string') return null
  return [value.first_name, value.last_name].filter(Boolean).join(' ') || value.email
}

function productObject(row: ProductSubmission): Product | null {
  return row.product && typeof row.product === 'object' ? row.product : null
}

const STATUS_STYLE: Record<string, { bg: string; color: string }> = {
  ready: { bg: '#DEEBFB', color: '#2563A8' },
  submitted: { bg: '#FBEBD3', color: '#9A6400' },
  waiting: { bg: '#FBEBD3', color: '#9A6400' },
  changes_requested: { bg: '#FBE2D8', color: '#9E3B1C' },
  approved: { bg: '#D8EFE7', color: '#14745D' },
  rejected: { bg: '#F6CDBC', color: '#9E3B1C' },
}

function statusStyle(status: string | null | undefined) {
  return STATUS_STYLE[status ?? ''] ?? { bg: '#EEF1F6', color: '#5A6883' }
}

export function SubmissionsPage() {
  const { businessUnit, searchQuery } = useAppState()
  const [rows, setRows] = useState<ProductSubmission[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let active = true
    fetchSubmissions({ businessUnit, search: searchQuery })
      .then((next) => { if (active) setRows(next) })
      .catch((error) => {
        console.error(error)
        if (active) setRows([])
      })
      .finally(() => { if (active) setLoading(false) })
    return () => { active = false }
  }, [businessUnit, searchQuery])

  const groups = useMemo(() => {
    const map = new Map<string, ProductSubmission[]>()
    for (const row of rows) {
      const key = titleCase(row.status)
      ;(map.get(key) ?? map.set(key, []).get(key)!).push(row)
    }
    return [...map.entries()]
  }, [rows])

  if (loading) {
    return <div className="flex h-full items-center justify-center text-sm" style={{ color: '#94A0B5' }}>Loading submissions...</div>
  }

  return (
    <div className="h-full overflow-y-auto bg-white">
      <div className="mx-auto flex max-w-[1480px] flex-col gap-5 px-7 py-6">
        <div>
          <h1 className="text-[22px] font-extrabold leading-tight" style={{ color: '#1B2840' }}>Submissions</h1>
          <p className="mt-1 text-[13.5px]" style={{ color: '#5A6883' }}>
            Internal reviews, licensor submissions, buyer submissions, PPS, packaging, and production approvals
          </p>
        </div>

        {rows.length === 0 ? (
          <EmptyState label="No submissions match this filter yet." />
        ) : (
          <div className="space-y-6">
            {groups.map(([status, items]) => (
              <section key={status}>
                <GroupHeader label={status} count={items.length} />
                <div className="overflow-hidden rounded-lg border" style={{ borderColor: '#EAEEF5' }}>
                  <table className="w-full text-left">
                    <thead>
                      <tr style={{ borderBottom: '1px solid #EAEEF5' }}>
                        {(['Product', 'Type', 'Recipient', 'Submitted', 'Expected', 'Proof', 'Revision', 'Action'] as const).map((h) => (
                          <th key={h} className="bg-white px-4 py-3 text-[11px] font-bold uppercase tracking-[0.04em]" style={{ color: '#94A0B5', width: h === 'Product' ? '30%' : undefined }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>{items.map((row) => (
                      <SubmissionRow
                        key={row.id}
                        row={row}
                        onUpdated={(next) => setRows((prev) => prev.map((item) => item.id === next.id ? { ...item, ...next } : item))}
                      />
                    ))}</tbody>
                  </table>
                </div>
              </section>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

function nextSubmissionStep(status: string | null | undefined): { status: string; label: string } | null {
  if (!status || status === 'ready') return { status: 'submitted', label: 'Submit' }
  if (status === 'submitted') return { status: 'waiting', label: 'Wait' }
  if (status === 'waiting' || status === 'changes_requested') return { status: 'approved', label: 'Approve' }
  return null
}

function SubmissionRow({ row, onUpdated }: { row: ProductSubmission; onUpdated: (row: ProductSubmission) => void }) {
  const product = productObject(row)
  const summary = product ? productToSummary(product) : null
  const status = statusStyle(row.status)
  const [busy, setBusy] = useState(false)
  const next = nextSubmissionStep(row.status)

  async function advance() {
    if (!next || busy) return
    setBusy(true)
    try {
      const updated = await updateSubmissionStatus(row.id, next.status)
      onUpdated({ ...row, ...updated, status: next.status })
    } catch (error) {
      console.error(error)
    } finally {
      setBusy(false)
    }
  }

  return (
    <tr className="transition-colors hover:bg-[#F6F8FC]" style={{ borderBottom: '1px solid #EAEEF5' }}>
      <td className="px-4 py-3">
        <p className="line-clamp-1 text-[13px] font-semibold" style={{ color: '#1B2840' }}>
          {summary ? summary.title : 'No product linked'}
        </p>
        <p className="mt-0.5 line-clamp-1 text-[12px]" style={{ color: '#5A6883' }}>
          {[summary?.businessUnit, summary?.retailerName, summary?.buyerName, summary?.licensorName].filter(Boolean).join(' · ') || relationName(row.project)}
        </p>
      </td>
      <td className="px-4 py-3">
        <span className="rounded-md px-2 py-0.5 text-[11px] font-bold" style={{ background: status.bg, color: status.color }}>
          {titleCase(row.submission_type)}
        </span>
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {[titleCase(row.recipient_type), relationName(row.licensor)].filter(Boolean).join(' · ')}
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        <div>{formatDate(row.submitted_at)}</div>
        <div className="mt-0.5 text-[12px]" style={{ color: '#94A0B5' }}>{userName(row.submitted_by)}</div>
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>{formatDate(row.expected_response_at)}</td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {row.portal_url ? (
          <a href={row.portal_url} target="_blank" rel="noreferrer" className="inline-flex items-center gap-1 font-semibold" style={{ color: '#0094FF' }}>
            <ExternalLink className="size-3.5" />
            {row.portal_reference || row.brand_assurance_number || 'Portal'}
          </a>
        ) : row.brand_assurance_number ? (
          <span className="inline-flex items-center gap-1"><FileCheck2 className="size-3.5" />{row.brand_assurance_number}</span>
        ) : '—'}
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: row.revision_required ? '#D2502B' : '#5A6883' }}>
        {row.revision_required ? 'Required' : '—'}
      </td>
      <td className="px-4 py-3">
        {next ? (
          <button
            type="button"
            onClick={advance}
            disabled={busy}
            className="inline-flex h-8 items-center gap-1 rounded-lg border px-2.5 text-[12px] font-bold transition-colors hover:bg-[#F6F8FC] disabled:opacity-50"
            style={{ borderColor: '#EAEEF5', color: '#1B2840' }}
          >
            <ArrowRight className="size-3.5" />
            {busy ? 'Saving...' : next.label}
          </button>
        ) : (
          <span className="text-[12px]" style={{ color: '#94A0B5' }}>—</span>
        )}
      </td>
    </tr>
  )
}

function GroupHeader({ label, count }: { label: string; count: number }) {
  return (
    <div className="mb-3 flex items-center gap-2">
      <Send className="size-4" style={{ color: '#0094FF' }} />
      <h2 className="text-[14px] font-bold" style={{ color: '#1B2840' }}>{label}</h2>
      <span className="rounded px-1.5 py-0.5 text-[11px] font-semibold" style={{ background: '#EAEEF5', color: '#5A6883' }}>{count}</span>
    </div>
  )
}

function EmptyState({ label }: { label: string }) {
  return (
    <div className="rounded-lg border px-5 py-10 text-center text-[13.5px]" style={{ borderColor: '#EAEEF5', color: '#94A0B5' }}>
      <UserRound className="mx-auto mb-2 size-6" />
      {label}
    </div>
  )
}

import { readItems } from '@directus/sdk'
import { directus } from '@/lib/directus'
import type { Order } from '@/lib/types'
import type { BusinessUnit } from '@/domain/products/types'

export interface FetchOrdersOpts {
  search?: string
  businessUnit?: BusinessUnit
  limit?: number
}

function businessUnitClause(businessUnit: BusinessUnit | undefined): unknown[] {
  if (!businessUnit || businessUnit === 'Unknown') return []
  if (businessUnit === 'Licensed') return [{ product: { business_unit: { _in: ['POP', 'POP Creations'] } } }]
  if (businessUnit === 'Generic') return [{ product: { business_unit: { _in: ['Spruce', 'Spruce Line'] } } }]
  return [{ product: { business_unit: { _eq: 'Software' } } }]
}

function searchClause(search: string | undefined): unknown[] {
  const q = search?.trim()
  if (!q) return []
  return [{
    _or: [
      { order_number: { _icontains: q } },
      { product: { code: { _icontains: q } } },
      { product: { name: { _icontains: q } } },
    ],
  }]
}

export async function fetchOrders(opts: FetchOrdersOpts = {}): Promise<Order[]> {
  const { limit = 300 } = opts
  return directus.request(
    readItems('order', {
      fields: [
        'id',
        'order_number',
        'order_date',
        'quantity',
        { retailer: ['id', 'name'] },
        { buyer: ['id', 'name'] },
        {
          product: [
            'id',
            'code',
            'name',
            'business_unit',
            { stage: ['id', 'name'] },
            { project: ['id', 'title', { retailer: ['id', 'name'] }, { buyer: ['id', 'name'] }] },
            { design: ['id', 'name', 'status', 'theme'] },
            { licensor: ['id', 'name'] },
            { property: ['id', 'name'] },
            { product_type: ['id', 'name'] },
          ],
        },
      ],
      filter: { _and: [...businessUnitClause(opts.businessUnit), ...searchClause(opts.search)] } as never,
      sort: ['-order_date', 'order_number'],
      limit,
    }),
  ) as Promise<Order[]>
}

import { useEffect, useMemo, useState } from 'react'
import { ReceiptText, Search } from 'lucide-react'
import { productToSummary } from '@/domain/products/adapters'
import type { Order, Product } from '@/lib/types'
import { useAppState } from '@/lib/appState'
import { fetchOrders } from './api'

function relationName(value: unknown): string | null {
  if (!value || typeof value === 'string') return null
  if (typeof value === 'object' && 'name' in value && typeof value.name === 'string') return value.name
  if (typeof value === 'object' && 'title' in value && typeof value.title === 'string') return value.title
  return null
}

function formatDate(iso: string | null): string {
  if (!iso) return 'No order date'
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

function productObject(order: Order): Product | null {
  return order.product && typeof order.product === 'object' ? order.product : null
}

export function OrdersPage() {
  const { businessUnit, searchQuery } = useAppState()
  const [orders, setOrders] = useState<Order[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let active = true
    fetchOrders({ businessUnit, search: searchQuery })
      .then((next) => { if (active) setOrders(next) })
      .catch((error) => {
        console.error(error)
        if (active) setOrders([])
      })
      .finally(() => { if (active) setLoading(false) })
    return () => { active = false }
  }, [businessUnit, searchQuery])

  const grouped = useMemo(() => {
    const map = new Map<string, Order[]>()
    for (const order of orders) {
      const product = productObject(order)
      const retailer = relationName(order.retailer) ?? relationName(product?.project && typeof product.project === 'object' ? product.project.retailer : null) ?? 'No retailer'
      ;(map.get(retailer) ?? map.set(retailer, []).get(retailer)!).push(order)
    }
    return [...map.entries()].sort(([a], [b]) => a.localeCompare(b))
  }, [orders])

  if (loading) {
    return (
      <div className="flex h-full items-center justify-center text-sm" style={{ color: '#94A0B5' }}>
        Loading orders...
      </div>
    )
  }

  return (
    <div className="h-full overflow-y-auto bg-white">
      <div className="mx-auto flex max-w-[1480px] flex-col gap-5 px-7 py-6">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div>
            <h1 className="text-[22px] font-extrabold leading-tight" style={{ color: '#1B2840' }}>
              Orders
            </h1>
            <p className="mt-1 text-[13.5px]" style={{ color: '#5A6883' }}>
              {orders.length.toLocaleString()} purchase-order record{orders.length === 1 ? '' : 's'} in this view
            </p>
          </div>
          <div className="flex items-center gap-2 rounded-lg border px-3 py-2 text-[12.5px]" style={{ borderColor: '#EAEEF5', color: '#5A6883' }}>
            <Search className="size-4" />
            <span>{searchQuery.trim() ? `Searching "${searchQuery.trim()}"` : 'Use sidebar search'}</span>
          </div>
        </div>

        {orders.length === 0 ? (
          <div className="rounded-lg border px-5 py-10 text-center text-[13.5px]" style={{ borderColor: '#EAEEF5', color: '#94A0B5' }}>
            No orders match this filter.
          </div>
        ) : (
          <div className="space-y-6">
            {grouped.map(([retailer, rows]) => (
              <section key={retailer}>
                <div className="mb-3 flex items-center gap-2">
                  <h2 className="text-[14px] font-bold" style={{ color: '#1B2840' }}>{retailer}</h2>
                  <span className="rounded px-1.5 py-0.5 text-[11px] font-semibold" style={{ background: '#EAEEF5', color: '#5A6883' }}>
                    {rows.length}
                  </span>
                </div>
                <div className="overflow-hidden rounded-lg border" style={{ borderColor: '#EAEEF5' }}>
                  <table className="w-full text-left">
                    <thead>
                      <tr style={{ borderBottom: '1px solid #EAEEF5' }}>
                        {(['Order', 'Product', 'Project', 'Buyer', 'Date', 'Qty'] as const).map((header) => (
                          <th
                            key={header}
                            className="bg-white px-4 py-3 text-[11px] font-bold uppercase tracking-[0.04em]"
                            style={{ color: '#94A0B5', width: header === 'Product' ? '28%' : undefined }}
                          >
                            {header}
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {rows.map((order) => <OrderRow key={order.id} order={order} />)}
                    </tbody>
                  </table>
                </div>
              </section>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

function OrderRow({ order }: { order: Order }) {
  const product = productObject(order)
  const summary = product ? productToSummary(product) : null
  const project = product?.project && typeof product.project === 'object' ? product.project : null
  const buyer = relationName(order.buyer) ?? relationName(project?.buyer) ?? 'No buyer'

  return (
    <tr className="transition-colors hover:bg-[#F6F8FC]" style={{ borderBottom: '1px solid #EAEEF5' }}>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <span className="flex size-7 shrink-0 items-center justify-center rounded-lg" style={{ background: '#FBEBD3' }}>
            <ReceiptText className="size-3.5" style={{ color: '#C8942A' }} />
          </span>
          <span className="text-[13px] font-semibold" style={{ color: '#1B2840' }}>
            {order.order_number ?? '(no order number)'}
          </span>
        </div>
      </td>
      <td className="px-4 py-3">
        <div className="min-w-0">
          <p className="line-clamp-1 text-[13px] font-semibold" style={{ color: '#1B2840' }}>
            {summary ? summary.title : 'No product linked'}
          </p>
          <p className="mt-0.5 line-clamp-1 text-[12px]" style={{ color: '#5A6883' }}>
            {[summary?.businessUnit, summary?.productTypeName, summary?.stageName].filter(Boolean).join(' · ') || 'No product context'}
          </p>
        </div>
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {summary?.projectTitle ?? 'No project'}
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {buyer}
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {formatDate(order.order_date)}
      </td>
      <td className="px-4 py-3 text-[13px] font-semibold" style={{ color: '#1B2840' }}>
        {order.quantity?.toLocaleString() ?? '—'}
      </td>
    </tr>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { CheckCircle2, FilePenLine, Paperclip, UserRoundCheck } from 'lucide-react'
import { productToSummary } from '@/domain/products/adapters'
import { useAppState } from '@/lib/appState'
import type { DirectusUser, Product, RevisionRequest } from '@/lib/types'
import { fetchRevisions, updateRevisionStatus } from '@/features/workflow/api'

function titleCase(value: string | null | undefined) {
  return (value ?? 'unknown').replaceAll('_', ' ').replace(/\b\w/g, (c) => c.toUpperCase())
}

function formatDate(iso: string | null | undefined) {
  if (!iso) return 'No date'
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

function relationName(value: unknown): string | null {
  if (!value || typeof value === 'string') return null
  if (typeof value === 'object' && 'name' in value && typeof value.name === 'string') return value.name
  if (typeof value === 'object' && 'title' in value && typeof value.title === 'string') return value.title
  return null
}

function userName(value: string | DirectusUser | null | undefined) {
  if (!value || typeof value === 'string') return null
  return [value.first_name, value.last_name].filter(Boolean).join(' ') || value.email
}

function productObject(row: RevisionRequest): Product | null {
  return row.product && typeof row.product === 'object' ? row.product : null
}

const STATUS_STYLE: Record<string, { bg: string; color: string }> = {
  open: { bg: '#FBEBD3', color: '#9A6400' },
  in_progress: { bg: '#DEEBFB', color: '#2563A8' },
  resolved: { bg: '#D8EFE7', color: '#14745D' },
  accepted: { bg: '#D8EFE7', color: '#14745D' },
  rejected: { bg: '#FBE2D8', color: '#9E3B1C' },
  canceled: { bg: '#EEF1F6', color: '#5A6883' },
}

function statusStyle(status: string | null | undefined) {
  return STATUS_STYLE[status ?? ''] ?? { bg: '#EEF1F6', color: '#5A6883' }
}

export function RevisionsPage() {
  const { businessUnit, searchQuery } = useAppState()
  const [rows, setRows] = useState<RevisionRequest[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let active = true
    fetchRevisions({ businessUnit, search: searchQuery })
      .then((next) => { if (active) setRows(next) })
      .catch((error) => {
        console.error(error)
        if (active) setRows([])
      })
      .finally(() => { if (active) setLoading(false) })
    return () => { active = false }
  }, [businessUnit, searchQuery])

  const groups = useMemo(() => {
    const map = new Map<string, RevisionRequest[]>()
    for (const row of rows) {
      const key = titleCase(row.status)
      ;(map.get(key) ?? map.set(key, []).get(key)!).push(row)
    }
    return [...map.entries()]
  }, [rows])

  if (loading) return <div className="flex h-full items-center justify-center text-sm" style={{ color: '#94A0B5' }}>Loading revisions...</div>

  return (
    <div className="h-full overflow-y-auto bg-white">
      <div className="mx-auto flex max-w-[1480px] flex-col gap-5 px-7 py-6">
        <div>
          <h1 className="text-[22px] font-extrabold leading-tight" style={{ color: '#1B2840' }}>Reviews / Revisions</h1>
          <p className="mt-1 text-[13.5px]" style={{ color: '#5A6883' }}>
            Change requests from creative directors, licensors, buyers, factories, and internal review
          </p>
        </div>

        {rows.length === 0 ? (
          <EmptyState label="No revision requests match this filter yet." />
        ) : (
          <div className="space-y-6">
            {groups.map(([status, items]) => (
              <section key={status}>
                <GroupHeader label={status} count={items.length} />
                <div className="grid gap-3 xl:grid-cols-2">
                  {items.map((row) => (
                    <RevisionCard
                      key={row.id}
                      row={row}
                      onUpdated={(next) => setRows((prev) => prev.map((item) => item.id === next.id ? { ...item, ...next } : item))}
                    />
                  ))}
                </div>
              </section>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

function canResolve(status: string | null | undefined) {
  return !['resolved', 'accepted', 'rejected', 'canceled'].includes(status ?? '')
}

function RevisionCard({ row, onUpdated }: { row: RevisionRequest; onUpdated: (row: RevisionRequest) => void }) {
  const product = productObject(row)
  const summary = product ? productToSummary(product) : null
  const status = statusStyle(row.status)
  const [busy, setBusy] = useState(false)

  async function resolve() {
    if (!canResolve(row.status) || busy) return
    setBusy(true)
    try {
      const updated = await updateRevisionStatus(row.id, 'resolved')
      onUpdated({ ...row, ...updated, status: 'resolved', resolved_at: updated.resolved_at ?? new Date().toISOString() })
    } catch (error) {
      console.error(error)
    } finally {
      setBusy(false)
    }
  }

  return (
    <article className="rounded-lg border p-4" style={{ borderColor: '#EAEEF5' }}>
      <div className="flex items-start justify-between gap-4">
        <div className="min-w-0">
          <h2 className="line-clamp-1 text-[14px] font-bold" style={{ color: '#1B2840' }}>
            {summary ? summary.title : relationName(row.design) ?? 'Revision request'}
          </h2>
          <p className="mt-1 line-clamp-1 text-[12.5px]" style={{ color: '#5A6883' }}>
            {[summary?.businessUnit, summary?.retailerName, summary?.buyerName, summary?.licensorName].filter(Boolean).join(' · ') || relationName(row.project)}
          </p>
        </div>
        <span className="shrink-0 rounded-md px-2 py-0.5 text-[11px] font-bold" style={{ background: status.bg, color: status.color }}>
